import json
import pymysql
import os

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=5
        )
        
        query_params = {}
        
        if event.get('queryStringParameters'):
            query_params = event['queryStringParameters']
        elif event.get('body'):
            body = json.loads(event['body']) if isinstance(event['body'], str) else event['body']
            query_params = body
        
        sql_query, sql_params = build_search_query(query_params)
        
        with connection.cursor() as cursor:
            cursor.execute(sql_query, sql_params)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': True,
                'count': len(results),
                'data': results
            }, default=str)
        }
        
    except pymysql.MySQLError as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': f'Database error: {str(e)}'
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': f'Error: {str(e)}'
            })
        }
        
    finally:
        if connection:
            connection.close()


def build_search_query(params):
    base_query = "SELECT * FROM products"
    where_clauses = []
    sql_params = []
    
    if params.get('product_id'):
        where_clauses.append("product_id = %s")
        sql_params.append(params['product_id'])
    
    if params.get('name'):
        where_clauses.append("name LIKE %s")
        sql_params.append(f"%{params['name']}%")
    
    if params.get('category'):
        where_clauses.append("category = %s")
        sql_params.append(params['category'])
    
    if params.get('min_price'):
        where_clauses.append("price >= %s")
        sql_params.append(float(params['min_price']))
    
    if params.get('max_price'):
        where_clauses.append("price <= %s")
        sql_params.append(float(params['max_price']))
    
    if params.get('in_stock'):
        if params['in_stock'].lower() in ['true', '1', 'yes']:
            where_clauses.append("stock_quantity > 0")
    
    if params.get('brand'):
        where_clauses.append("brand = %s")
        sql_params.append(params['brand'])
    
    if params.get('description'):
        where_clauses.append("description LIKE %s")
        sql_params.append(f"%{params['description']}%")
    
    if params.get('sku'):
        where_clauses.append("sku = %s")
        sql_params.append(params['sku'])
    
    if params.get('tags'):
        where_clauses.append("tags LIKE %s")
        sql_params.append(f"%{params['tags']}%")
    
    if params.get('status'):
        where_clauses.append("status = %s")
        sql_params.append(params['status'])
    
    if params.get('created_after'):
        where_clauses.append("created_at >= %s")
        sql_params.append(params['created_after'])
    
    if params.get('created_before'):
        where_clauses.append("created_at <= %s")
        sql_params.append(params['created_before'])
    
    if where_clauses:
        base_query += " WHERE " + " AND ".join(where_clauses)
    
    order_by = params.get('order_by', 'product_id')
    valid_order_columns = ['product_id', 'name', 'price', 'created_at', 'stock_quantity', 'category']
    if order_by in valid_order_columns:
        order_direction = params.get('order_direction', 'ASC').upper()
        if order_direction in ['ASC', 'DESC']:
            base_query += f" ORDER BY {order_by} {order_direction}"
    
    limit = int(params.get('limit', 100))
    if limit > 0 and limit <= 1000:
        base_query += f" LIMIT {limit}"
    
    offset = int(params.get('offset', 0))
    if offset > 0:
        base_query += f" OFFSET {offset}"
    
    return base_query, sql_params